import{_ as t,o,c as r,ae as a}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Preparing for iOS 14.5 Release FAQ","description":"","frontmatter":{"title":"Preparing for iOS 14.5 Release FAQ","slug":"preparing-for-ios-14-release-faq"},"headers":[],"relativePath":"marketer-hub/preparing-for-ios-14-release-faq.md","filePath":"marketer-hub/preparing-for-ios-14-release-faq.md"}'),i={name:"marketer-hub/preparing-for-ios-14-release-faq.md"};function n(s,e,l,p,d,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<p>This article contains FAQs that are relevant to the iOS 14.5 release.</p><details><summary>What actions do Branch customers need to take to prepare for iOS 14?</summary><p>We recommend confirming the following three actions have been taken to complete your iOS 14 updates:</p><ol><li><strong>Ensure SKAdNetwork (SKAN) implementation.</strong> SKAdNetwork is Apple&#39;s attribution framework, facilitating ad measurement without device-level data. SKAdNetwork integration instructions are available <a href="./enable-skadnetwork-via-branch-sdk.html">here</a>.</li><li><strong>Decide whether to show the App Tracking Transparency prompt, and integrate it if you decide to do so.</strong> If you want to continue receiving device-level ad attribution data, your users will need to opt in via the new ATT permissions prompt. Technical implementation steps are available <a href="./ios-advanced-features.html#include-apples-attrackingmanager">here</a>. We have also published <a href="https://blog.branch.io/best-practices-user-opt-in-ios-14/" target="_blank" rel="noreferrer">a blog post</a> with implementation best practices to optimize your opt-in rate.</li><li><strong>Engage with your ad networks to test SKAN-based attribution.</strong> We recommend reaching out to your network partners to discuss any campaign configuration updates. For a list of ad networks that have completed SKAN setup, <a href="./skadnetwork.html#ad-network-support">click here</a>.</li></ol><p>For more information, please check out these additional resources:</p><ul><li><a href="https://branch.io/ios-14/" target="_blank" rel="noreferrer"><strong>Branch iOS 14 Resource Hub</strong></a><strong>.</strong> Central location for everything related to iOS 14 from Branch.</li><li><a href="https://branch.io/ios-14-readiness-checklist/" target="_blank" rel="noreferrer"><strong>iOS 14 Readiness Checklist</strong></a><strong>.</strong> Interactive tool to help you check your readiness plans.</li><li><a href="/faq/docs/ios-14-faqs.html"><strong>iOS 14 FAQs</strong></a><strong>.</strong> Our full collection of iOS 14 FAQs.</li></ul></details><details><summary>What happens if I do not make any updates to prepare for iOS 14?</summary><p>If you do not take any action to update your iOS configuration for iOS 14, you will lose <em>all</em> insight into your paid app acquisition campaigns for users on iOS 14.5 and above.</p><p>At minimum, you should plan to add support for SKAdNetwork. If you want to continue receiving device-level ad attribution data, your users will need to opt in via the new ATT permissions prompt. For more details on recommended steps, see this FAQ answer: <a href="./what-actions-do-branch-customers-need-to-take-before-the-ios-145-release.html">What actions do Branch customers need to take to prepare for iOS 14?</a></p></details><details><summary>Do I need to update the Branch SDK for iOS 14?</summary><p>You will need to update your app to support Apple&#39;s SKAdNetwork. If you want to use the Branch SDK to automatically invoke the relevant methods (recommended), you will need to ensure you&#39;re using SDK v.0.35.0+. If you are integrating these methods yourself, or using another SDK to do so, no Branch SDK update is required.</p><p>Branch iOS SDK versions 1.39.2+ additionally capture ATT opt-in/opt-out events when users interact with the new AppTrackingTransparency prompt. This update is optional, but provides additional data to help you understand your user flows.</p><p><strong>Note for Cocoapods users:</strong> if you have <code>platform :ios, &#39;8.0&#39;</code> in your podfile, you will need to update this to <code>&#39;9.0&#39;</code> to get the latest Branch SDK.</p></details>',4)])])}const m=t(i,[["render",n]]);export{h as __pageData,m as default};
